using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>().ToContainer("Products");

        // EF Core 9: default discriminator property renamed from "Discriminator" to "$type".
        // Existing 500K documents use "Discriminator", and direct SQL queries reference c.Discriminator.
        modelBuilder.Entity<Product>().HasDiscriminator<string>("Discriminator");

        // EF Core 9: id values no longer include the discriminator prefix.
        // Existing documents store id as "Product|123"; preserve that format.
        modelBuilder.Entity<Product>().HasRootDiscriminatorInJsonId(true);

        // EF Core 9: HasIndex() on Cosmos entities now throws at startup.
        // Removed — manage indexing via the Cosmos DB indexing policy instead.
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

